        tokenStats: {totalInput: 0, totalOutput: 0, lastInput: 0, lastOutput: 0},
        discarded: false,
        discardedChapter: null,
        userInputCache: '',
        progressLog: [],
        currentProfile: 'standard',
        enabledAgents: [],
